import { useCanvas } from '../hooks/useCanvas.js';
import { BarCanvasProps, BarCanvasInstance } from '../types/canvas-shape.js';
import { printBarBuilder } from '../utils/shapes/bar-canvas.js';

export function BarCanvas<Datum>(props: BarCanvasProps<Datum>) {
  const {
    strokeWidth,
    isVertical = true,
    enableDotOverflow = false,
    overlayPadding,
    ...propsBarCanvas
  } = props;

  // Build how Line canvas should style
  const drawBars = printBarBuilder<Datum>(
    strokeWidth,
    enableDotOverflow,
    overlayPadding,
  );

  // Define draw method for entire Bars shape
  const drawBarCanvas = (
    ctx: CanvasRenderingContext2D,
    canvas: BarCanvasInstance<Datum>,
  ) => {
    drawBars(ctx, canvas, canvas.x, canvas.y, canvas.width, canvas.height);
  };

  const barCanvas = {
    ...propsBarCanvas,
    isVertical,
  };

  useCanvas('bar', (ctx: CanvasRenderingContext2D) =>
    drawBarCanvas(ctx, barCanvas),
  );

  return null;
}
